import sys

class TrieNode:
    def __init__(self):
        self.count = 0
        self.is_end_of_word = False
        self.children = {}

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for ch in word:
            if ch not in node.children:
                node.children[ch] = TrieNode()
            node = node.children[ch]
        node.is_end_of_word = True

class Solution:
    def __init__(self):
        self.trie = Trie()

    def search(self, word):
        node = self.trie.root
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return True

