#include <iostream>
#include <string>
#include <vector>

using namespace std;

class TrieNode {
 public:
  int count;
  bool isEndOfWord;
  TrieNode* child[26];
};

class Trie {
 public:
  TrieNode* root;
  Trie() { root = new TrieNode(); }

  void insert(const string &word) {
   TrieNode *node = root;
   for(char ch : word) {
    if(node->child[ch - 'a'] == nullptr) {
     node->child[ch - 'a'] = new TrieNode();
    }
    node = node->child[ch - 'a'];
   }
   node->isEndOfWord = true;
  }

  bool search(const string &word) {
   TrieNode *node = root;
   for(char ch : word) {
    if(node->child[ch - 'a'] == nullptr) {
     return false;
    }
    node = node->child[ch - 'a'];
   }
   return true;
  }
};

class Solution {
 public:
  Trie trie;

  void solve() {
   int n;
   cin >> n;
   for(int i = 0; i < n; i++) {
    string word;
    cin >> word;
    if(trie.search(word)) {
     cout << "yes" << endl;
    } else {
     cout << "no" << endl;
    }
   }
  }
};

int main() {
 Solution solution;
 solution.solve();
 return 0;
